#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int binary_search(int arr[], int n, int x) {
    int low = 0;
    int high = n - 1;
    while (low <= high) {
        int mid = (low + high) / 2;
        if (arr[mid] == x)
            return mid;
        else if (arr[mid] < x)
            low = mid + 1;
        else
            high = mid - 1;
    }
    return -1;
}

int min_swaps(int arr[], int n, int x) {
    int index = binary_search(arr, n, x);
    if (index == -1)
        return -1;
    int swaps = 0;
    for (int i = 0; i < index; i++) {
        if (arr[i] > arr[index])
            swaps++;
    }
    return swaps;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, q;
        scanf("%d %d", &n, &q);
        int arr[n];
        for (int i = 0; i < n; i++)
            scanf("%d", &arr[i]);
        while (q--) {
            int x;
            scanf("%d", &x);
            printf("%d\n", min_swaps(arr, n, x));
        }
    }
    return 0;
}

